SELECT "NCT", "Author", "Originial publication or Follow-up", "Class of ICI", "Name of ICI", "Priamry Multiple, composite, or co-primary endpoints?", "Primary endpoint" 
FROM clinical_trials 
WHERE "Class of ICI" IN ('PD-L1', 'CTLA-4', 'PD-L1, CTLA-4') AND "Priamry Multiple, composite, or co-primary endpoints?" = 'Co-primary';

SELECT "NCT", "Author", "Year", "Originial publication or Follow-up", "Name of ICI", "Trial phase", "Cancer type", "Trial name", "Treatment regimen" 
FROM clinical_trials 
WHERE "Name of ICI" = 'Durvalumab, Tremelimumab' AND "Cancer type" = 'Colorectal' AND "Trial phase" = 'Phase 2' AND "Originial publication or Follow-up" = 'Original publication';
